+        fn poll(self: Pin<&mut Self>, cx: &mut Context<'_>) -> Poll<Self::Output> {
+            let this = self.get_mut();
+
+            if this.left_out.is_none() {
+                if let Poll::Ready(value) = Pin::new(&mut this.left).poll(cx) {
+                    this.left_out = Some(value);
